import React from "react";

const MOTION_PROPS = new Set([
  "animate",
  "drag",
  "dragConstraints",
  "dragElastic",
  "exit",
  "initial",
  "layout",
  "layoutId",
  "transition",
  "variants",
  "whileFocus",
  "whileHover",
  "whileInView",
  "whileTap",
  "viewport",
]);

function stripMotionProps(props: Record<string, unknown>) {
  const clean: Record<string, unknown> = {};
  Object.entries(props).forEach(([key, value]) => {
    if (!MOTION_PROPS.has(key)) clean[key] = value;
  });
  return clean;
}

function createMotionElement(tag: string) {
  return React.forwardRef<HTMLElement, Record<string, unknown>>((props, ref) =>
    React.createElement(tag, { ...stripMotionProps(props), ref }),
  );
}

export const motion = new Proxy({}, {
  get(_target, tag: string) {
    return createMotionElement(tag);
  },
}) as Record<string, React.ForwardRefExoticComponent<Record<string, unknown> & React.RefAttributes<HTMLElement>>>;

export function AnimatePresence({ children }: { children: React.ReactNode }) {
  return <>{children}</>;
}

export function useInView() {
  return true;
}

export function useMotionValue<T>(initial: T) {
  return {
    get: () => initial,
    set: () => undefined,
    on: () => () => undefined,
  };
}

export function useSpring<T>(value: T) {
  return value;
}

export function animate(
  from: number,
  to: number,
  options?: { duration?: number; onUpdate?: (value: number) => void },
) {
  const duration = Math.max(0, (options?.duration ?? 0.2) * 1000);
  const start = performance.now();
  let frame = 0;

  const tick = (now: number) => {
    const progress = duration ? Math.min(1, (now - start) / duration) : 1;
    options?.onUpdate?.(from + (to - from) * progress);
    if (progress < 1) frame = window.requestAnimationFrame(tick);
  };

  frame = window.requestAnimationFrame(tick);
  return {
    stop: () => window.cancelAnimationFrame(frame),
  };
}
