const CLICK_PREFIX = "calc_clicks_";
const USE_PREFIX = "calc_uses_";

type ActivityType = "clicks" | "uses";

const storageAvailable = () => typeof window !== "undefined" && !!window.localStorage;

export const calculatorIdFromPath = (path: string) => {
  const cleanPath = path.split("?")[0].split("#")[0].replace(/\/+$/, "");
  return cleanPath.replace(/^\//, "");
};

const keyFor = (path: string, type: ActivityType) => {
  const id = calculatorIdFromPath(path);
  return `${type === "clicks" ? CLICK_PREFIX : USE_PREFIX}${id}`;
};

export function incrementCalculatorActivity(path: string, type: ActivityType) {
  if (!storageAvailable()) return;
  const key = keyFor(path, type);
  const current = Number.parseInt(window.localStorage.getItem(key) || "0", 10);
  window.localStorage.setItem(key, String(Number.isFinite(current) ? current + 1 : 1));
}

export function getCalculatorActivityScores() {
  const scores: Record<string, number> = {};
  if (!storageAvailable()) return scores;

  for (let i = 0; i < window.localStorage.length; i += 1) {
    const key = window.localStorage.key(i);
    if (!key) continue;

    const isClickKey = key.startsWith(CLICK_PREFIX);
    const isUseKey = key.startsWith(USE_PREFIX);
    if (!isClickKey && !isUseKey) continue;

    const id = key.slice(isClickKey ? CLICK_PREFIX.length : USE_PREFIX.length);
    const value = Number.parseInt(window.localStorage.getItem(key) || "0", 10);
    if (!id || !Number.isFinite(value) || value <= 0) continue;
    scores[id] = (scores[id] || 0) + value;
  }

  return scores;
}

export function getRankedCalculatorTools<T extends { href: string }>(
  allTools: readonly T[],
  fallbackTools: readonly T[],
  limit: number,
) {
  const scores = getCalculatorActivityScores();
  const originalOrder = new Map(allTools.map((tool, index) => [tool.href, index]));

  const ranked = allTools
    .map((tool) => ({
      tool,
      score: scores[calculatorIdFromPath(tool.href)] || 0,
      index: originalOrder.get(tool.href) || 0,
    }))
    .filter(({ score }) => score > 0)
    .sort((a, b) => b.score - a.score || a.index - b.index)
    .map(({ tool }) => tool);

  const selected = ranked.slice(0, limit);
  const selectedHrefs = new Set(selected.map((tool) => tool.href));

  for (const fallback of fallbackTools) {
    if (selected.length >= limit) break;
    if (selectedHrefs.has(fallback.href)) continue;
    selected.push(fallback);
    selectedHrefs.add(fallback.href);
  }

  return selected.slice(0, limit);
}
